          '3분기': { start: `${year}-07-01`, end: `${year}-09-30`, label: '3분기' },
          '4분기': { start: `${year}-10-01`, end: `${year}-12-31`, label: '4분기' },
          '전체': { start: `${year}-01-01`, end: `${year}-12-31`, label: '전체' },
